**REST endpoint (external-facing) that delegates to a bank account verification provider, with merchant lookup via gRPC to account-service.**

```kotlin
// payment-service: routes/MerchantBankVerificationRoute.kt

@RestController
@RequestMapping("/v1/merchants/{merchantId}/bank-account")
class MerchantBankVerificationController(
    private val accountServiceClient: AccountServiceGrpcClient,
    private val bankVerificationService: BankVerificationService,
) {
    @PostMapping("/verify")
    suspend fun verifyBankAccount(
        @PathVariable merchantId: String,
        @Valid @RequestBody request: BankVerificationRequest,
    ): BankVerificationResponse {
        // gRPC call to account-service to confirm merchant exists + is active
        val merchant = accountServiceClient.getMerchant(merchantId)
            ?: throw ResponseStatusException(HttpStatus.NOT_FOUND)

        val result = bankVerificationService.verify(
            routingNumber = request.routingNumber,
            accountNumber = request.accountNumber,
            accountHolderName = request.accountHolderName,
        )

        return BankVerificationResponse(
            merchantId = merchantId,
            status = result.status, // VERIFIED, FAILED, PENDING
            verifiedAt = result.verifiedAt,
        )
    }
}

data class BankVerificationRequest(
    @field:NotBlank val routingNumber: String,
    @field:NotBlank val accountNumber: String,
    @field:NotBlank val accountHolderName: String,
)

data class BankVerificationResponse(
    val merchantId: String,
    val status: VerificationStatus,
    val verifiedAt: Instant?,
)

enum class VerificationStatus { VERIFIED, FAILED, PENDING }
```

